// Worked focus: cmem-recursion-depth-budget — Bound recursion by adversarial input depth, frame cost, and target stack limits or replace it with explicit storage.
/* Evidence: cmem-worked-cmem-automatic-lifetime-stack-3 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 9905; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_automatic_lifetime_stack_3(const int *work, size_t count, size_t maximum, int *sum) {
  size_t index;
  int total = 0;
  if (work == NULL || sum == NULL || count > maximum) return 0;
  for (index = 0; index < count; ++index) total += work[index];
  *sum = total;
  return 1;
}

int main(void) {
  int explicit_stack[4] = { 5, 6, 7, 8 };
  int sum = 0;
  int accepted = worked_cmem_automatic_lifetime_stack_3(explicit_stack, 4, 4, &sum);
  int rejected = worked_cmem_automatic_lifetime_stack_3(explicit_stack, 4, 3, &sum);
  int invariant = accepted && !rejected && sum == 26;
  printf("stack sum=%d invariant=%d\n", sum, invariant);
  return invariant ? 0 : 1;
}

